	if (!Array.isArray(exam.questions) || exam.questions.length === 0) return false;
	if (!exam.questions.some(isPublishableExamQuestion)) return false;
	return Boolean(exam.publishable === true || [
		"final_text_verified",
		"text_only_no_pdf_no_image",
		"typed_questions_pdf_fidelity_checked"
	].includes(exam.contentMode) || exam.sourceStatus === "uploaded_from_question_bank" || exam.sourceFile === "سؤال تایپ‌شده داخل سایت" || exam.sourceMode === "متن داخل سایت");
