var normalizeAdvisorText = (text = "") => text.replace(/ي/g, "ی").replace(/ك/g, "ک").replace(/[٠-٩]/g, (digit) => "٠١٢٣٤٥٦٧٨٩".indexOf(digit)).replace(/[۰-۹]/g, (digit) => "۰۱۲۳۴۵۶۷۸۹".indexOf(digit)).replace(/(.)\1{1,}/g, "$1").toLowerCase();
var findAdvisorSignal = (text, signals, fallback) => signals.find((signal) => signal.words.some((word) => text.includes(normalizeAdvisorText(word)))) || fallback;
var extractAdvisorProfileHint = (text = "") => {
	const normalized = normalizeAdvisorText(text);
	const grade = normalized.includes("دهم") ? "دهم" : normalized.includes("یازدهم") ? "یازدهم" : normalized.includes("دوازدهم") ? "دوازدهم" : normalized.includes("کنکور") ? "کنکوری" : "";
	const track = normalized.includes("تجربی") ? "تجربی" : normalized.includes("ریاضی") ? "ریاضی" : "";
	return {
		grade,
		track,
		isProfileAnswer: Boolean(grade || track) && normalized.length < 80
	};
};
